module top_module(
  input a,
  input b,
  input c,
  input d,
  output out
);wire unused_ab, cd, not_cd;

  // AND gate for a and b
  assign unused_ab = a & b;

  // OR gate for c and d
  assign cd = c | d;

  // NOT gate for cd
  assign not_cd = ~cd;

  // AND gate for unused_ab and not_cd
  assign out = unused_ab & not_cd;

endmodule
